class Solution {
    public int findTargetSumWays(int[] nums, int target) {
        int sum = 0;
        for (int num : nums) sum += num;
        if ((sum + target) % 2 != 0 || sum < Math.abs(target)) return 0;
        int T = (sum + target) / 2;
        int[] dp = new int[T + 1];
        dp[0] = 1;
        for (int num : nums) {
            for (int j = T; j >= num; j--) {
                dp[j] += dp[j - num];
            }
        }
        return dp[T];
    }
}
